pub fn findUpper(cp: u21) ?u21 {
    var lo: usize = 0;
    var hi: usize = upcase_table.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        if (upcase_table[mid].from == cp) return upcase_table[mid].to;
        if (upcase_table[mid].from < cp) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    return null;
}

