pub fn findFold(cp: u21) ?u21 {
    var lo: usize = 0;
    var hi: usize = fold_table.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        if (fold_table[mid].from == cp) return fold_table[mid].to;
        if (fold_table[mid].from < cp) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    return null;
}

