pub fn containsU21(comptime table: []const u21, cp: u21) bool {
    var lo: usize = 0;
    var hi: usize = table.len;
    while (lo < hi) {
        const mid = lo + (hi - lo) / 2;
        if (table[mid] == cp) return true;
        if (table[mid] < cp) {
            lo = mid + 1;
        } else {
            hi = mid;
        }
    }
    return false;
}

